import buildlogic.OptionalDependenciesPomAction

plugins {
    id("buildlogic.client-conventions")
    id("buildlogic.spring-boot-3-conventions")
    id("com.gradleup.shadow")
}

publishing {
    publications.named<MavenPublication>("maven") {
        pom.withXml(
            OptionalDependenciesPomAction(
                setOf(
                    "io.micrometer:micrometer-core",
                    "org.springframework.boot:spring-boot-actuator-autoconfigure",
                )
            )
        )
    }
}

val baseStarterProjectDir = project(":camunda-spring-boot-starter").projectDir
val generatedTestSourcesDir = layout.buildDirectory.dir("generated-test-sources/java")

val testSourceGenerator by sourceSets.creating {
    java.srcDir(baseStarterProjectDir.resolve("src/test/test-source-generator"))
    compileClasspath += sourceSets["main"].output + sourceSets["main"].compileClasspath
    runtimeClasspath += output + compileClasspath
}

sourceSets.named("test") {
    java.srcDir(baseStarterProjectDir.resolve("src/test/java"))
    java.srcDir(generatedTestSourcesDir)
    resources.srcDir(baseStarterProjectDir.resolve("src/test/resources"))
    compileClasspath += testSourceGenerator.output
    runtimeClasspath += testSourceGenerator.output
}

val generateJobWorkerPermutations by tasks.registering(JavaExec::class) {
    dependsOn(tasks.named(testSourceGenerator.classesTaskName))
    inputs.dir(baseStarterProjectDir.resolve("src/test/test-source-generator"))
    outputs.dir(generatedTestSourcesDir)
    classpath = testSourceGenerator.runtimeClasspath
    mainClass.set("io.camunda.client.spring.test.util.JobWorkerPermutationsGenerator")
    args(generatedTestSourcesDir.get().asFile.absolutePath)
}

tasks.named("compileTestJava") {
    dependsOn(generateJobWorkerPermutations)
}

tasks.named<JavaCompile>("compileTestJava") {
    exclude(
        "io/camunda/client/impl/CamundaObjectMapperTest.java",
        "io/camunda/client/spring/configuration/JsonMapperConfigurationTest.java",
    )
}

dependencies {
    implementation(project(":camunda-spring-boot-starter")) {
        exclude(group = "org.springframework.boot", module = "spring-boot-health")
    }
    api(project(":camunda-client-java"))
    api(libs.io.micrometer.micrometer.core)
    api(libs.org.springframework.spring.beans)
    api(libs.org.springframework.boot.spring.boot.autoconfigure)
    api(libs.org.springframework.boot.spring.boot.actuator.autoconfigure)
    implementation(libs.org.springframework.boot.spring.boot.actuator)
    implementation(libs.org.slf4j.slf4j.api)

    testImplementation(libs.org.aspectj.aspectjweaver)
    testImplementation(libs.org.springframework.spring.web)
    testImplementation(libs.org.springframework.spring.test)
    testImplementation(libs.org.wiremock.wiremock.standalone)
    testImplementation(libs.org.mockito.mockito.junit.jupiter)
    testImplementation(libs.org.mockito.mockito.core)
    testImplementation(libs.org.springframework.boot.spring.boot.test)

    compileOnly(libs.org.jboss.forge.roaster.roaster.api)
    add(testSourceGenerator.implementationConfigurationName, libs.org.jboss.forge.roaster.roaster.api)
    add(testSourceGenerator.runtimeOnlyConfigurationName, libs.org.jboss.forge.roaster.roaster.jdt)
}

tasks.named<com.github.jengelman.gradle.plugins.shadow.tasks.ShadowJar>("shadowJar") {
    archiveClassifier.set("")
    dependencies {
        include(project(":camunda-spring-boot-starter"))
    }
    // SB4-specific classes that reference spring-boot-health (SB4 only) are overridden by the
    // SB3 starter's own source files, which have the same FQN but extend SB3 actuator types.
    // Shadow plugin processes project classes first; shaded-dep duplicates are excluded by default.
    // Do NOT add top-level exclude() for these class paths — that would also remove the project's
    // own SB3 versions that have the same path.
    mergeServiceFiles()
    // Merge AutoConfiguration.imports so SB3's registration survives; Spring Boot deduplicates
    // the same entry if it also appears in the SB4 starter's jar on the classpath.
    mergeServiceFiles("META-INF/spring")
}

tasks.named<Jar>("jar") {
    enabled = false
}

// ResourceUtils.getFile("classpath:...") requires real filesystem paths — it cannot resolve
// resources from inside a JAR. The base starter's main output must appear as directories on the
// test classpath rather than being consumed via its published JAR.
val baseStarter = project(":camunda-spring-boot-starter")
tasks.named<Test>("test") {
    dependsOn(
        baseStarter.tasks.named("compileJava"),
        baseStarter.tasks.named("processResources"),
    )
    classpath = files(
        baseStarter.layout.buildDirectory.dir("classes/java/main"),
        baseStarter.layout.buildDirectory.dir("resources/main"),
    ) + classpath
}

// Use the shadow jar as the runtime artifact for inter-project dependencies.
// The shadow jar shades and excludes SB4-specific classes (CamundaActuatorConfiguration,
// CamundaClientHealthIndicator) that reference spring-boot-health (SB4 only) — preventing
// classpath conflicts when consumers force Spring Boot to 3.5.x.
configurations {
    named("runtimeElements") {
        outgoing.artifacts.clear()
        outgoing.artifact(tasks.named("shadowJar"))
    }
}

(publishing.publications["maven"] as MavenPublication).artifact(tasks.named("shadowJar"))

description = "Camunda Spring Boot 3 Starter"
